1	//! Role-gating extractors.
2	//!
3	//! Each handler that mutates state declares which roles are permitted by adding
4	//! one of these extractors to its signature. The extractor pulls `CurrentUser`
5	//! out of the request extensions (set by `session_middleware`) and returns
6	//! `AppError::Auth` when no session is present or `AppError::Forbidden` when the
7	//! session belongs to a user whose role is not in the allow-list.
8	
9	use axum::{async_trait, extract::FromRequestParts, http::request::Parts};
10	use shared::UserRole;
11	
12	use crate::error::AppError;
13	use crate::middleware::session::CurrentUser;
14	use crate::models::user::User;
15	
16	/// Helper used by handlers that already extracted `CurrentUser`. Returns Ok if
17	/// the user's role is one of `allowed`, else `AppError::Forbidden`.
18	pub fn require_any_role(user: &User, allowed: &[UserRole]) -> Result<(), AppError> {
19	    let role = UserRole::from_str(&user.role).ok_or(AppError::Forbidden)?;
20	    if allowed.contains(&role) {
21	        Ok(())
22	    } else {
23	        Err(AppError::Forbidden)
24	    }
25	}
26	
27	/// Generic role-set extractor — instantiate with the allowed roles per route.
28	/// Handlers use the type-aliased newtypes below for readability.
29	pub struct AuthenticatedUser(pub User);
30	
31	#[async_trait]
32	impl<S: Send + Sync> FromRequestParts<S> for AuthenticatedUser {
33	    type Rejection = AppError;
34	    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
35	        let CurrentUser(user) = parts
36	            .extensions
37	            .get::<CurrentUser>()
38	            .cloned()
39	            .ok_or(AppError::Auth)?;
40	        Ok(AuthenticatedUser(user))
41	    }
42	}
43	
44	macro_rules! role_extractor {
45	    ($name:ident, $($variant:ident),+ $(,)?) => {
46	        #[doc = concat!("Role-gated extractor allowing: ", stringify!($($variant),+))]
47	        pub struct $name(pub User);
48	
49	        #[async_trait]
50	        impl<S: Send + Sync> FromRequestParts<S> for $name {
51	            type Rejection = AppError;
52	            async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
53	                let CurrentUser(user) = parts
54	                    .extensions
55	                    .get::<CurrentUser>()
56	                    .cloned()
57	                    .ok_or(AppError::Auth)?;
58	                let role = UserRole::from_str(&user.role).ok_or(AppError::Forbidden)?;
59	                let allowed = &[$(UserRole::$variant),+];
60	                if allowed.contains(&role) {
61	                    Ok($name(user))
62	                } else {
63	                    Err(AppError::Forbidden)
64	                }
65	            }
66	        }
67	    };
68	}
69	
70	role_extractor!(RequireAdmin, Administrator);
71	role_extractor!(RequireCurator, Administrator, ContentCurator);
72	role_extractor!(RequireReviewer, Administrator, Reviewer);
73	role_extractor!(RequireFinance, Administrator, FinanceManager);
74	role_extractor!(RequireStore, Administrator, StoreManager);
