191	pub async fn upload_evidence(
192	    State(state): State<AppState>,
193	    RequireReviewer(user): RequireReviewer,
194	    Path(outcome_id): Path<String>,
195	    mut multipart: Multipart,
196	) -> AppResult<Json<EvidenceFile>> {
197	    let mut bytes_field: Option<Vec<u8>> = None;
198	    let mut filename = String::from("upload.bin");
199	    let mut declared_mime = String::from("application/octet-stream");
200	
201	    while let Some(field) = multipart
202	        .next_field()
203	        .await
204	        .map_err(|e| AppError::Validation(format!("multipart: {e}")))?
205	    {
206	        let name = field.name().unwrap_or("").to_string();
207	        if name == "file" {
208	            if let Some(fname) = field.file_name() {
209	                filename = fname.to_string();
210	            }
211	            if let Some(ct) = field.content_type() {
212	                declared_mime = ct.to_string();
213	            }
214	            let data = field
215	                .bytes()
216	                .await
217	                .map_err(|e| AppError::Validation(format!("multipart bytes: {e}")))?;
218	            bytes_field = Some(data.to_vec());
219	        }
220	    }
221	    let bytes = bytes_field.ok_or_else(|| AppError::Validation("missing 'file' field".into()))?;
222	
223	    let file_svc = FileService::new(
224	        state.db.clone(),
225	        *state.encryption_key,
226	        (*state.evidence_dir).clone(),
227	    );
228	    let row = file_svc
229	        .upload_evidence(&outcome_id, &bytes, &filename, &declared_mime, &user.id)
230	        .await?;
231	    AuditService::new(state.db.clone())
232	        .log(
233	            &user.id,
234	            AuditAction::UploadEvidence,
235	            "evidence_file",
236	            Some(&row.id),
237	            None,
238	            Some(AuditService::compute_hash(&row.sha256_fingerprint)),
239	            None,
240	        )
241	        .await?;
242	    Ok(Json(row))
243	}
