429	    /// Download a completed report by id + token. The token is **single-use**:
430	    /// after a successful read it is cleared from the row so the same URL
431	    /// cannot be reused.
432	    pub async fn download_report(
433	        &self,
434	        report_id: &str,
435	        token: &str,
436	    ) -> AppResult<(String, Vec<u8>)> {
437	        let row: Option<ScheduledReport> = sqlx::query_as::<_, ScheduledReport>(
438	            "SELECT * FROM scheduled_reports WHERE id = ?",
439	        )
440	        .bind(report_id)
441	        .fetch_optional(&self.db)
442	        .await?;
443	        let row = row.ok_or(AppError::NotFound)?;
444	        if row.status != "complete" {
445	            return Err(AppError::Conflict("report not yet complete".into()));
446	        }
447	        let stored_token = row.download_token.as_deref().unwrap_or("");
448	        if stored_token.is_empty() || stored_token != token {
449	            return Err(AppError::NotFound);
450	        }
451	        let path = row.file_path.as_deref().ok_or(AppError::NotFound)?;
452	        let bytes = std::fs::read(path)?;
453	        // Single-use: clear the token so the same URL cannot be reused.
454	        sqlx::query("UPDATE scheduled_reports SET download_token = NULL WHERE id = ?")
455	            .bind(report_id)
456	            .execute(&self.db)
457	            .await?;
458	        let mime = if path.ends_with(".pdf") {
459	            "application/pdf".to_string()
460	        } else {
461	            "text/csv".to_string()
462	        };
463	        Ok((mime, bytes))
464	    }
465	}
