14	use tracing_subscriber::EnvFilter;
15	
16	#[tokio::main]
17	async fn main() -> AppResult<()> {
18	    tracing_subscriber::fmt()
19	        .with_env_filter(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
20	        .with_target(false)
21	        .compact()
22	        .init();
23	
24	    let database_url = std::env::var("DATABASE_URL")
25	        .unwrap_or_else(|_| "sqlite:///app/data/scholarvault.db".to_string());
26	    let encryption_key_material = std::env::var("ENCRYPTION_KEY")
27	        .unwrap_or_else(|_| "scholarvault-aes256-key-32bytes!!".to_string());
28	    let signing_key = std::env::var("SIGNING_KEY")
29	        .unwrap_or_else(|_| "scholarvault-jwt-signing-key-secret!".to_string());
30	    let host = std::env::var("HOST").unwrap_or_else(|_| "0.0.0.0".to_string());
31	    let port: u16 = std::env::var("PORT")
32	        .unwrap_or_else(|_| "3000".to_string())
33	        .parse()
34	        .map_err(|e| AppError::Internal(format!("invalid PORT: {e}")))?;
35	    let migrations_dir = std::env::var("MIGRATIONS_DIR")
36	        .unwrap_or_else(|_| "/app/migrations".to_string());
37	
38	    ensure_data_dir(&database_url)?;
39	
40	    tracing::info!(%database_url, "opening sqlite pool");
41	    let pool = db::init_pool(&database_url).await?;
42	
43	    db::run_migrations(&pool, &migrations_dir).await?;
44	
45	    let evidence_dir = std::path::PathBuf::from(
46	        std::env::var("EVIDENCE_DIR").unwrap_or_else(|_| "/app/evidence".to_string()),
47	    );
48	    let backup_dir = std::path::PathBuf::from(
49	        std::env::var("BACKUP_DIR").unwrap_or_else(|_| "/app/backups".to_string()),
50	    );
51	    let reports_dir = std::path::PathBuf::from(
52	        std::env::var("REPORTS_DIR").unwrap_or_else(|_| "/app/reports".to_string()),
53	    );
54	    let _ = std::fs::create_dir_all(&evidence_dir);
55	    let _ = std::fs::create_dir_all(&backup_dir);
56	    let _ = std::fs::create_dir_all(&reports_dir);
57	
58	    let state = AppState {
59	        db: pool,
60	        encryption_key: Arc::new(derive_key(&encryption_key_material)),
61	        signing_key: Arc::new(signing_key),
62	        rate_limit: RateLimitState::new(60),
63	        evidence_dir: Arc::new(evidence_dir),
64	        backup_dir: Arc::new(backup_dir),
65	        reports_dir: Arc::new(reports_dir),
66	    };
67	
68	    // Start the backup scheduler so the SPEC default 02:00 daily job is wired.
69	    let backup_service = Arc::new(BackupService::new(
70	        state.db.clone(),
71	        match database_url.strip_prefix("sqlite://") {
72	            Some(rest) => std::path::PathBuf::from(rest),
73	            None => std::path::PathBuf::from(&database_url),
74	        },
75	        (*state.evidence_dir).clone(),
76	        (*state.backup_dir).clone(),
77	        *state.encryption_key,
78	    ));
79	    let cron_expr = std::env::var("BACKUP_SCHEDULE").unwrap_or_else(|_| "0 0 2 * * *".to_string());
80	    let _scheduler_handle = match start_backup_scheduler(backup_service, &cron_expr).await {
81	        Ok(s) => Some(s),
82	        Err(e) => {
83	            tracing::warn!(error = ?e, "backup scheduler failed to start (continuing without)");
84	            None
85	        }
86	    };
87	
88	    let app = build_router(state);
89	
90	    let addr: SocketAddr = format!("{host}:{port}")
91	        .parse()
92	        .map_err(|e| AppError::Internal(format!("bad bind address: {e}")))?;
93	    tracing::info!(%addr, "ScholarVault listening");
94	
95	    let listener = tokio::net::TcpListener::bind(addr)
96	        .await
97	        .map_err(|e| AppError::Internal(format!("bind failed: {e}")))?;
98	    axum::serve(
99	        listener,
100	        app.into_make_service_with_connect_info::<SocketAddr>(),
101	    )
102	    .await
103	    .map_err(|e| AppError::Internal(format!("serve failed: {e}")))?;
104	
105	    Ok(())
106	}
107	
108	/// Ensure the parent directory of a `sqlite://...` URL exists so SQLite can
109	/// create the database file at startup.
110	fn ensure_data_dir(database_url: &str) -> AppResult<()> {
111	    if let Some(rest) = database_url.strip_prefix("sqlite://") {
112	        let path = std::path::Path::new(rest);
113	        if let Some(parent) = path.parent() {
114	            if !parent.as_os_str().is_empty() {
115	                std::fs::create_dir_all(parent)
116	                    .map_err(|e| AppError::Internal(format!("create data dir: {e}")))?;
117	            }
118	        }
119	    }
120	    Ok(())
121	}
