1	//! Database setup. Initializes a SQLite pool with WAL journal mode and a busy
2	//! timeout, and exposes a `run_migrations` helper that loads SQL files from the
3	//! configured migrations directory at runtime.
4	
5	use sqlx::sqlite::{SqliteConnectOptions, SqliteJournalMode, SqlitePoolOptions};
6	use sqlx::SqlitePool;
7	use std::path::Path;
8	use std::str::FromStr;
9	use std::time::Duration;
10	
11	use crate::error::{AppError, AppResult};
12	
13	/// Open a SQLite connection pool against `database_url`. Enables WAL mode for
14	/// better concurrent read/write throughput and sets a 5-second busy timeout so
15	/// transactions retry instead of failing immediately under contention.
16	pub async fn init_pool(database_url: &str) -> AppResult<SqlitePool> {
17	    let options = SqliteConnectOptions::from_str(database_url)
18	        .map_err(|e| AppError::Internal(format!("invalid DATABASE_URL: {e}")))?
19	        .create_if_missing(true)
20	        .journal_mode(SqliteJournalMode::Wal)
21	        .busy_timeout(Duration::from_secs(5));
22	
23	    let pool = SqlitePoolOptions::new()
24	        .max_connections(8)
25	        .acquire_timeout(Duration::from_secs(10))
26	        .connect_with(options)
27	        .await?;
28	
29	    sqlx::query("PRAGMA foreign_keys = ON;")
30	        .execute(&pool)
31	        .await?;
32	
33	    Ok(pool)
34	}
35	
36	/// Run all SQL migration files found under `migrations_dir`. Uses the runtime
37	/// `Migrator::new` so the directory is read at startup rather than embedded at
38	/// compile time — this lets the same binary serve any environment.
39	pub async fn run_migrations(pool: &SqlitePool, migrations_dir: &str) -> AppResult<()> {
40	    let path = Path::new(migrations_dir);
41	    if !path.exists() {
42	        tracing::warn!(dir = %migrations_dir, "migrations directory does not exist; skipping");
43	        return Ok(());
44	    }
45	    let migrator = sqlx::migrate::Migrator::new(path)
46	        .await
47	        .map_err(|e| AppError::Internal(format!("migrator load failed: {e}")))?;
48	    migrator
49	        .run(pool)
50	        .await
51	        .map_err(|e| AppError::Internal(format!("migration run failed: {e}")))?;
52	    tracing::info!(dir = %migrations_dir, "migrations applied");
53	    Ok(())
54	}
