35	/// Derive a 32-byte AES-256 key from an arbitrary-length string by truncating or
36	/// right-padding with zeroes. Used so the operator can configure the key as plain
37	/// text in `.env` while the cipher still receives a fixed-size byte array.
38	pub fn derive_key(material: &str) -> [u8; 32] {
39	    let bytes = material.as_bytes();
40	    let mut out = [0u8; 32];
41	    let n = bytes.len().min(32);
42	    out[..n].copy_from_slice(&bytes[..n]);
43	    out
44	}
