1	//! Session-loader middleware.
2	//!
3	//! Reads the `sv_session` cookie from the request, looks the session row up in
4	//! SQLite, and — if it is still alive — attaches a `CurrentUser` extension to
5	//! the request so handlers and the `require_role` extractor can read it.
6	//!
7	//! Expired sessions are deleted from the table on first sight; missing or
8	//! malformed cookies are silently ignored (the request continues unauthenticated).
9	
10	use axum::{
11	    body::Body,
12	    extract::{Request, State},
13	    middleware::Next,
14	    response::Response,
15	};
16	use axum_extra::extract::cookie::CookieJar;
17	use chrono::{DateTime, Utc};
18	
19	use crate::models::user::User;
20	use crate::AppState;
21	
22	/// Wrapper newtype attached to request extensions when a session is active.
23	/// Handlers extract it via the `FromRequestParts` impl in `require_role.rs`.
24	#[derive(Clone, Debug)]
25	pub struct CurrentUser(pub User);
26	
27	#[derive(Clone, Debug)]
28	pub struct CurrentSession {
29	    pub session_id: String,
30	    pub csrf_token: String,
31	}
32	
33	/// Axum middleware: pulls the session cookie, loads the user, and attaches
34	/// `CurrentUser` + `CurrentSession` extensions if everything checks out.
35	pub async fn session_middleware(
36	    State(state): State<AppState>,
37	    cookies: CookieJar,
38	    mut req: Request<Body>,
39	    next: Next,
40	) -> Response {
41	    if let Some(session_cookie) = cookies.get("sv_session") {
42	        let session_id = session_cookie.value().to_string();
43	        if let Some((user, csrf_token)) = load_session_user(&state, &session_id).await {
44	            req.extensions_mut().insert(CurrentUser(user));
45	            req.extensions_mut().insert(CurrentSession {
46	                session_id,
47	                csrf_token,
48	            });
49	        }
50	    }
51	    next.run(req).await
52	}
53	
54	async fn load_session_user(state: &AppState, session_id: &str) -> Option<(User, String)> {
55	    #[derive(sqlx::FromRow)]
56	    struct SessionRow {
57	        user_id: String,
58	        csrf_token: String,
59	        expires_at: String,
60	    }
61	
62	    let row: Option<SessionRow> = sqlx::query_as::<_, SessionRow>(
63	        "SELECT user_id, csrf_token, expires_at FROM sessions WHERE id = ?",
64	    )
65	    .bind(session_id)
66	    .fetch_optional(&state.db)
67	    .await
68	    .ok()
69	    .flatten();
70	
71	    let row = row?;
72	
73	    // Reject expired sessions and clean them up.
74	    if let Ok(exp) = DateTime::parse_from_rfc3339(&row.expires_at) {
75	        if exp.with_timezone(&Utc) < Utc::now() {
76	            let _ = sqlx::query("DELETE FROM sessions WHERE id = ?")
77	                .bind(session_id)
78	                .execute(&state.db)
79	                .await;
80	            return None;
81	        }
82	    }
83	
84	    let user: Option<User> =
85	        sqlx::query_as::<_, User>("SELECT * FROM users WHERE id = ? AND is_active = 1")
86	            .bind(&row.user_id)
87	            .fetch_optional(&state.db)
88	            .await
89	            .ok()
90	            .flatten();
91	
92	    user.map(|u| (u, row.csrf_token))
93	}
94

