            "SELECT * FROM scheduled_reports WHERE id = ?",
        )
        .bind(report_id)
        .fetch_optional(&self.db)
        .await?;
        let row = row.ok_or(AppError::NotFound)?;
        if !is_admin && row.created_by != requesting_user_id {
            return Err(AppError::Forbidden);
        }
        if row.status != "complete" {
