#[tokio::test]
async fn test_download_report_rejects_other_user() {
    let pool = fresh_db().await;
    let tmp = std::env::temp_dir().join(format!("sv-test-{}", uuid::Uuid::new_v4()));
    std::fs::create_dir_all(&tmp).unwrap();
