143	async fn test_evidence_upload_duplicate_fingerprint_returns_409() {
144	    let (app, _state) = setup_test_app().await;
145	    let (session, csrf) = login_as(app.clone(), "reviewer", "Scholar2024!").await;
146	    let cookie = format!("{}; csrf_token={}", session, csrf);
147	
148	    let req = Request::builder()
149	        .method(Method::POST)
150	        .uri("/api/outcomes")
151	        .header("content-type", "application/json")
152	        .header("cookie", cookie.clone())
153	        .header("X-CSRF-Token", csrf.clone())
154	        .body(Body::from(
155	            json!({"type":"paper","title":"With evidence","abstract_snippet":"x","certificate_number":null}).to_string(),
156	        ))
157	        .unwrap();
158	    let resp = app.clone().oneshot(req).await.unwrap();
159	    let bytes = to_bytes(resp.into_body(), 64 * 1024).await.unwrap();
160	    let outcome_id = serde_json::from_slice::<Value>(&bytes).unwrap()["outcome"]["id"]
161	        .as_str()
162	        .unwrap()
163	        .to_string();
164	
165	    // Build a real PDF byte payload via a multipart body string.
166	    let pdf: &[u8] = b"%PDF-1.4\n%\xe2\xe3\xcf\xd3\nrest";
167	    let boundary = "----test-boundary";
168	    let mut body = Vec::new();
169	    body.extend_from_slice(format!("--{}\r\n", boundary).as_bytes());
170	    body.extend_from_slice(
171	        b"Content-Disposition: form-data; name=\"file\"; filename=\"evidence.pdf\"\r\n",
172	    );
173	    body.extend_from_slice(b"Content-Type: application/pdf\r\n\r\n");
174	    body.extend_from_slice(pdf);
175	    body.extend_from_slice(format!("\r\n--{}--\r\n", boundary).as_bytes());
176	
177	    let req = Request::builder()
178	        .method(Method::POST)
179	        .uri(format!("/api/outcomes/{}/evidence", outcome_id))
180	        .header(
181	            "content-type",
182	            format!("multipart/form-data; boundary={}", boundary),
183	        )
184	        .header("cookie", cookie.clone())
185	        .header("X-CSRF-Token", csrf.clone())
186	        .body(Body::from(body.clone()))
187	        .unwrap();
188	    let resp = app.clone().oneshot(req).await.unwrap();
189	    assert_eq!(resp.status(), StatusCode::OK, "first upload must succeed");
190	
191	    // Same bytes again → 409
192	    let req = Request::builder()
193	        .method(Method::POST)
194	        .uri(format!("/api/outcomes/{}/evidence", outcome_id))
195	        .header(
196	            "content-type",
197	            format!("multipart/form-data; boundary={}", boundary),
198	        )
199	        .header("cookie", cookie.clone())
200	        .header("X-CSRF-Token", csrf)
201	        .body(Body::from(body))
202	        .unwrap();
203	    let resp = app.oneshot(req).await.unwrap();
204	    assert_eq!(
205	        resp.status(),
206	        StatusCode::CONFLICT,
207	        "duplicate upload should be rejected"
208	    );
209	}
