143	pub async fn get_order(
144	    State(state): State<AppState>,
145	    AuthenticatedUser(user): AuthenticatedUser,
146	    Path(id): Path<String>,
147	) -> AppResult<Json<OrderWithItems>> {
148	    use crate::error::AppError;
149	    use shared::UserRole;
150	    let svc = StoreService::new(state.db.clone());
151	    let (order, items) = svc.get_order_with_items(&id).await?;
152	    // Object-level authorization: administrators and store managers may read any
153	    // order; all other users may only read orders they placed themselves.
154	    let role = UserRole::from_str(&user.role);
155	    let privileged = matches!(
156	        role,
157	        Some(UserRole::Administrator) | Some(UserRole::StoreManager)
158	    );
159	    if !privileged && order.user_id != user.id {
160	        return Err(AppError::Forbidden);
161	    }
162	    Ok(Json(OrderWithItems { order, items }))
163	}
