169	}

1	//! Rate-limiting middleware.
2	//!
3	//! Backed by the `governor` crate's keyed rate limiter. The key is the
4	//! authenticated `user_id` when present, otherwise the client IP — so the limit
5	//! is "per actor" rather than per process. Quota defaults to **60 requests per
6	//! minute** as required by SPEC.md, and a 429 response includes a `Retry-After`
7	//! header so callers can back off cleanly.
8	
9	use std::num::NonZeroU32;
10	use std::sync::Arc;
11	
12	use axum::{
13	    body::Body,
14	    extract::{Request, State},
15	    http::{HeaderValue, StatusCode},
16	    middleware::Next,
17	    response::{IntoResponse, Response},
18	};
19	use governor::{
20	    clock::DefaultClock,
21	    state::keyed::DefaultKeyedStateStore,
22	    Quota, RateLimiter,
23	};
24	
25	use crate::middleware::session::CurrentUser;
26	use crate::AppState;
27	
28	/// Shared rate-limit state. Cloned into `AppState` so middleware can read it via
29	/// `State<AppState>`.
30	#[derive(Clone)]
31	pub struct RateLimitState {
32	    limiter: Arc<RateLimiter<String, DefaultKeyedStateStore<String>, DefaultClock>>,
33	}
34	
35	impl RateLimitState {
36	    /// Create a new keyed rate limiter at `per_minute` requests / 60 seconds.
37	    /// Defaults to 60 if the supplied value is zero.
38	    pub fn new(per_minute: u32) -> Self {
39	        // SAFETY: 60 is a non-zero literal, so the inner constructor never returns None.
40	        let fallback = NonZeroU32::new(60).unwrap_or(NonZeroU32::MIN);
41	        let n = NonZeroU32::new(per_minute).unwrap_or(fallback);
42	        let quota = Quota::per_minute(n);
43	        Self {
44	            limiter: Arc::new(RateLimiter::keyed(quota)),
45	        }
46	    }
47	
48	    /// Returns true when the request fits within the quota for `key`.
49	    pub fn check(&self, key: &str) -> bool {
50	        self.limiter.check_key(&key.to_string()).is_ok()
51	    }
52	}
53	
54	impl Default for RateLimitState {
55	    fn default() -> Self {
56	        Self::new(60)
57	    }
58	}
59	
60	/// Axum middleware: 60 requests per minute keyed by user_id (falls back to IP).
61	/// On overflow returns HTTP 429 with `Retry-After: 60`.
62	pub async fn rate_limit_middleware(
63	    State(state): State<AppState>,
64	    req: Request<Body>,
65	    next: Next,
66	) -> Response {
67	    // Choose the limiter key: user id when authenticated, else client IP, else 'anon'.
68	    let key = if let Some(CurrentUser(user)) = req.extensions().get::<CurrentUser>() {
69	        format!("user:{}", user.id)
70	    } else if let Some(ip) = req
71	        .headers()
72	        .get("X-Forwarded-For")
73	        .and_then(|v| v.to_str().ok())
74	    {
75	        format!("ip:{}", ip)
76	    } else {
77	        "anon".to_string()
78	    };
79	
80	    if state.rate_limit.check(&key) {
81	        next.run(req).await
82	    } else {
83	        let mut response =
84	            (StatusCode::TOO_MANY_REQUESTS, "rate limit exceeded").into_response();
85	        response
86	            .headers_mut()
87	            .insert("Retry-After", HeaderValue::from_static("60"));
88	        response
89	    }
90	}
