1	//! Backup, restore, and lifecycle cleanup service.
2	//!
3	//! Bundles the SQLite database file plus the encrypted evidence directory into
4	//! a single tarball, AES-256-GCM encrypts the bytes, writes the result to
5	//! `<backup_dir>/<timestamp>-<type>.bin`, and records metadata in
6	//! `backup_records`. The "type" classification follows SPEC.md:
7	//!
8	//!   • the **last day of every calendar month** → `monthly`
9	//!   • everything else                          → `daily`
10	//!
11	//! Restore validation runs against a sandbox copy: the bundle is decrypted into
12	//! `/tmp`, the contained SQLite file is opened with a fresh pool, and a
13	//! `PRAGMA integrity_check` + `SELECT COUNT(*) FROM users` is executed plus the
14	//! SHA-256 of the bundle file is verified against the recorded hash. Only when
15	//! all three checks pass is the live database overwritten.
16	
17	use chrono::{DateTime, Datelike, Duration, NaiveDate, Utc};
18	use flate2::{read::GzDecoder, write::GzEncoder, Compression};
19	use serde::{Deserialize, Serialize};
20	use sha2::{Digest, Sha256};
21	use sqlx::sqlite::{SqliteConnectOptions, SqlitePoolOptions};
22	use sqlx::SqlitePool;
23	use std::fs::{self, File};
24	use std::io::{Cursor, Read, Write};
25	use std::path::PathBuf;
26	use std::str::FromStr;
27	use uuid::Uuid;
28	
29	use crate::error::{AppError, AppResult};
30	use crate::models::backup::{BackupRecord, RetentionPolicy};
31	use crate::security::encryption;
32	
33	#[derive(Clone)]
34	pub struct BackupService {
35	    pub db: SqlitePool,
