43	pub struct SandboxValidationReport {
44	    pub hash_ok: bool,
45	    pub integrity_ok: bool,
46	    pub read_test_ok: bool,
47	    pub all_passed: bool,
48	    pub message: String,
49	}
50	
51	#[derive(Debug, Clone, Serialize, Deserialize)]
52	pub struct CleanupResult {
53	    pub purged_daily: i64,
54	    pub purged_monthly: i64,
