76	    pub async fn list_backups(&self) -> AppResult<Vec<BackupRecord>> {
77	        let rows = sqlx::query_as::<_, BackupRecord>(
78	            "SELECT * FROM backup_records ORDER BY created_at DESC LIMIT 200",
79	        )
