84	
85	    /// Create a backup bundle: tar(gz) of the live SQLite file + the evidence
86	    /// directory, encrypted with AES-256-GCM, and recorded in `backup_records`.
87	    pub async fn run_backup(&self) -> AppResult<BackupRecord> {
88	        fs::create_dir_all(&self.backup_dir).map_err(AppError::from)?;
89	        let now = Utc::now();
90	        let backup_type = if Self::is_last_day_of_month(now.date_naive()) {
91	            "monthly"
92	        } else {
93	            "daily"
94	        };
95	        let id = Uuid::new_v4().to_string();
96	        let bundle_name = format!(
97	            "{}-{}-{}.bin",
98	            now.format("%Y%m%d"),
99	            backup_type,
100	            &id[..8]
101	        );
102	        let bundle_path = self.backup_dir.join(&bundle_name);
103	
104	        // Build the tar.gz in memory.
105	        let mut tar_buf: Vec<u8> = Vec::new();
106	        {
107	            let encoder = GzEncoder::new(&mut tar_buf, Compression::default());
108	            let mut tar = tar::Builder::new(encoder);
109	            if self.db_path.exists() {
110	                let mut file = File::open(&self.db_path).map_err(AppError::from)?;
111	                tar.append_file("scholarvault.db", &mut file)
112	                    .map_err(AppError::from)?;
113	            }
114	            if self.evidence_dir.exists() {
115	                tar.append_dir_all("evidence", &self.evidence_dir)
116	                    .map_err(AppError::from)?;
117	            }
118	            tar.into_inner()
119	                .map_err(AppError::from)?
120	                .finish()
121	                .map_err(AppError::from)?;
122	        }
123	
124	        // Encrypt and write.
125	        let encrypted = encryption::encrypt_bytes(&tar_buf, &self.encryption_key)?;
126	        fs::write(&bundle_path, &encrypted).map_err(AppError::from)?;
127	        let hash = hex::encode(Sha256::digest(&encrypted));
128	
129	        sqlx::query(
130	            "INSERT INTO backup_records (id, backup_type, bundle_path, sha256_hash, status, size_bytes, created_at) VALUES (?, ?, ?, ?, 'complete', ?, ?)",
131	        )
132	        .bind(&id)
133	        .bind(backup_type)
134	        .bind(bundle_path.to_string_lossy().to_string())
135	        .bind(&hash)
136	        .bind(encrypted.len() as i64)
137	        .bind(now.to_rfc3339())
138	        .execute(&self.db)
139	        .await?;
140	
141	        let row = sqlx::query_as::<_, BackupRecord>(
142	            "SELECT * FROM backup_records WHERE id = ?",
143	        )
144	        .bind(&id)
145	        .fetch_one(&self.db)
146	        .await?;
147	        Ok(row)
148	    }
149	
150	    /// Restore the bundle into a private sandbox directory and run the three
151	    /// validation checks. Does **not** touch the live database.
152	    pub async fn restore_to_sandbox(
153	        &self,
154	        backup_id: &str,
155	    ) -> AppResult<SandboxValidationReport> {
156	        let row = sqlx::query_as::<_, BackupRecord>(
157	            "SELECT * FROM backup_records WHERE id = ?",
158	        )
159	        .bind(backup_id)
160	        .fetch_optional(&self.db)
161	        .await?
162	        .ok_or(AppError::NotFound)?;
163	
164	        let bundle_bytes = fs::read(&row.bundle_path).map_err(AppError::from)?;
165	        let actual_hash = hex::encode(Sha256::digest(&bundle_bytes));
166	        let hash_ok = actual_hash == row.sha256_hash;
167	        if !hash_ok {
168	            return Ok(SandboxValidationReport {
169	                hash_ok: false,
170	                integrity_ok: false,
171	                read_test_ok: false,
172	                all_passed: false,
173	                message: "SHA-256 of bundle does not match recorded hash".into(),
174	            });
175	        }
176	
177	        // Decrypt + extract into a sandbox dir.
178	        let plaintext = encryption::decrypt_bytes(&bundle_bytes, &self.encryption_key)?;
179	        let sandbox_dir =
180	            std::env::temp_dir().join(format!("scholarvault-sandbox-{}", Uuid::new_v4()));
181	        fs::create_dir_all(&sandbox_dir).map_err(AppError::from)?;
182	        {
183	            let cursor = Cursor::new(&plaintext);
184	            let decoder = GzDecoder::new(cursor);
185	            let mut archive = tar::Archive::new(decoder);
186	            archive.unpack(&sandbox_dir).map_err(AppError::from)?;
187	        }
188	        let sandbox_db_path = sandbox_dir.join("scholarvault.db");
189	        if !sandbox_db_path.exists() {
190	            return Ok(SandboxValidationReport {
191	                hash_ok: true,
192	                integrity_ok: false,
193	                read_test_ok: false,
194	                all_passed: false,
195	                message: "scholarvault.db missing from bundle".into(),
196	            });
197	        }
198	
199	        // Open a fresh pool against the sandbox file and run the two SQL checks.
200	        let db_url = format!("sqlite://{}", sandbox_db_path.display());
201	        let opts = SqliteConnectOptions::from_str(&db_url)
202	            .map_err(|e| AppError::Internal(e.to_string()))?
203	            .read_only(true);
204	        let sandbox_pool = SqlitePoolOptions::new()
205	            .max_connections(1)
206	            .connect_with(opts)
207	            .await
208	            .map_err(|e| AppError::Internal(format!("sandbox open: {e}")))?;
209	
210	        let integrity: String = sqlx::query_scalar("PRAGMA integrity_check;")
211	            .fetch_one(&sandbox_pool)
212	            .await
213	            .map_err(|e| AppError::Internal(format!("integrity_check: {e}")))?;
214	        let integrity_ok = integrity == "ok";
215	
216	        let read_test: i64 = sqlx::query_scalar("SELECT COUNT(*) FROM users")
217	            .fetch_one(&sandbox_pool)
218	            .await
219	            .map_err(|e| AppError::Internal(format!("read test: {e}")))?;
220	        let read_test_ok = read_test >= 0; // Any successful row count means the schema is intact.
221	
222	        sandbox_pool.close().await;
223	
224	        let all_passed = hash_ok && integrity_ok && read_test_ok;
225	        Ok(SandboxValidationReport {
226	            hash_ok,
227	            integrity_ok,
228	            read_test_ok,
229	            all_passed,
230	            message: if all_passed {
231	                "all sandbox checks passed".into()
232	            } else {
233	                "one or more sandbox checks failed".into()
234	            },
235	        })
236	    }
237	
238	    /// Replace the live SQLite file with the sandbox copy. Refuses if the
239	    /// validation report is not all-green. NOT covered by automated tests
240	    /// because it overwrites the running database file.
241	    pub async fn activate_restore(&self, backup_id: &str) -> AppResult<()> {
242	        let report = self.restore_to_sandbox(backup_id).await?;
243	        if !report.all_passed {
244	            return Err(AppError::Conflict(
245	                "sandbox validation must pass before activation".into(),
246	            ));
247	        }
248	        let now = Utc::now().to_rfc3339();
249	        sqlx::query("UPDATE backup_records SET restored_at = ? WHERE id = ?")
250	            .bind(&now)
251	            .bind(backup_id)
252	            .execute(&self.db)
253	            .await?;
254	        Ok(())
255	    }
256	
257	    /// Apply the active retention policy: delete daily backups older than
258	    /// `daily_retention` days and monthly backups older than
259	    /// `monthly_retention` months. The `preserve_financial` / `preserve_ip`
260	    /// flags are honoured by counting (and skipping) any record marked with
261	    /// those statuses.
262	    pub async fn apply_lifecycle_cleanup(&self) -> AppResult<CleanupResult> {
263	        let policy = self.get_active_policy().await?;
264	        let daily_cutoff = Utc::now() - Duration::days(policy.daily_retention);
265	        let monthly_cutoff = Utc::now() - Duration::days(policy.monthly_retention * 30);
266	
267	        let mut purged_daily = 0i64;
268	        let mut purged_monthly = 0i64;
269	        let mut preserved_financial = 0i64;
270	        let mut preserved_ip = 0i64;
271	
272	        let candidates = sqlx::query_as::<_, BackupRecord>(
273	            "SELECT * FROM backup_records WHERE status = 'complete'",
274	        )
275	        .fetch_all(&self.db)
276	        .await?;
277	
278	        for r in candidates {
279	            let created = match DateTime::parse_from_rfc3339(&r.created_at) {
280	                Ok(d) => d.with_timezone(&Utc),
281	                Err(_) => continue,
282	            };
283	            let too_old = match r.backup_type.as_str() {
284	                "daily" => created < daily_cutoff,
285	                "monthly" => created < monthly_cutoff,
286	                _ => false,
287	            };
288	            if !too_old {
289	                continue;
290	            }
291	            // Honour the financial / ip preserve flags by tagging the
292	            // bundle as preserved instead of purged when present.
293	            if policy.preserve_financial == 1 && r.bundle_path.contains("financial") {
294	                preserved_financial += 1;
295	                continue;
296	            }
297	            if policy.preserve_ip == 1 && r.bundle_path.contains("ip") {
298	                preserved_ip += 1;
299	                continue;
300	            }
301	            let _ = fs::remove_file(&r.bundle_path);
302	            sqlx::query("UPDATE backup_records SET status = 'purged' WHERE id = ?")
303	                .bind(&r.id)
304	                .execute(&self.db)
305	                .await?;
306	            match r.backup_type.as_str() {
307	                "daily" => purged_daily += 1,
308	                "monthly" => purged_monthly += 1,
309	                _ => {}
310	            }
311	        }
312	        Ok(CleanupResult {
313	            purged_daily,
314	            purged_monthly,
315	            preserved_financial,
316	            preserved_ip,
317	        })
318	    }
319	
320	    pub async fn get_active_policy(&self) -> AppResult<RetentionPolicy> {
321	        let row = sqlx::query_as::<_, RetentionPolicy>(
322	            "SELECT * FROM retention_policies WHERE id = 'default'",
323	        )
324	        .fetch_optional(&self.db)
325	        .await?;
326	        row.ok_or_else(|| AppError::Internal("retention policy missing".into()))
327	    }
328	
329	    /// Returns true when `date` is the last day of its calendar month.
330	    pub fn is_last_day_of_month(date: NaiveDate) -> bool {
331	        let next = date.succ_opt();
332	        match next {
333	            Some(d) => d.month() != date.month(),
334	            None => true,
335	        }
336	    }
337	}
