1	//! Pure-function helpers for the promotion / checkout UI: discount display
2	//! formatting and MM/DD/YYYY 12-hour datetime conversion.
3	
4	use chrono::{DateTime, NaiveDateTime};
5	
6	/// Formatted display of a promotion's discount value (e.g. "10%" or "$5.00 off").
7	pub fn format_discount(discount_type: &str, value: f64) -> String {
8	    match discount_type {
9	        "percent" => format!("{:.0}%", value),
10	        "fixed" => format!("${:.2} off", value),
11	        _ => "—".to_string(),
12	    }
13	}
14	
15	/// Convert an RFC 3339 / ISO 8601 timestamp to MM/DD/YYYY hh:mm AM/PM display.
16	pub fn iso_to_mmddyyyy(iso: &str) -> String {
17	    if let Ok(dt) = DateTime::parse_from_rfc3339(iso) {
18	        return dt.format("%m/%d/%Y %I:%M %p").to_string();
19	    }
20	    if let Ok(dt) = NaiveDateTime::parse_from_str(iso, "%Y-%m-%dT%H:%M:%S") {
21	        return dt.format("%m/%d/%Y %I:%M %p").to_string();
22	    }
23	    iso.to_string()
24	}
25	
26	/// Convert an HTML `datetime-local` value (`YYYY-MM-DDTHH:MM`) into an
27	/// RFC 3339 string suitable for posting to the backend.
28	pub fn datetime_local_to_iso(value: &str) -> String {
29	    if value.len() < 16 {
30	        return value.to_string();
31	    }
32	    format!("{}:00Z", &value[..16])
33	}
34	
35	/// Total currency saved across a list of line items, formatted with two decimals.
36	/// Adding `+ 0.0` normalises any IEEE 754 negative zero into positive zero so
37	/// the formatted output is never `"$-0.00"`.
38	pub fn format_total_savings(per_line: &[f64]) -> String {
39	    let total: f64 = per_line.iter().sum::<f64>() + 0.0;
40	    format!("${:.2}", total)
41	}
