1	//! Outcome / IP registration service.
2	//!
3	//! Two business rules from SPEC.md live here:
4	//!
5	//! 1. **Contribution shares must total exactly 100%** at submission time.
6	//!    Enforced in `submit_outcome`. `add_contributor` additionally rejects any
7	//!    addition that would push the running total over 100.
8	//! 2. **Duplicate detection** via Jaro-Winkler similarity (≥0.85 on title,
9	//!    ≥0.80 on the first 200 chars of the abstract, plus exact certificate
10	//!    number match) — implemented in `find_duplicates` and surfaced from
11	//!    `create_outcome` as a non-blocking candidate list.
12	
13	use chrono::{DateTime, Utc};
14	use serde::{Deserialize, Serialize};
15	use sqlx::SqlitePool;
16	use uuid::Uuid;
17	
18	use crate::error::{AppError, AppResult};
19	use crate::models::outcome::{Outcome, OutcomeContributor};
20	
21	pub const TITLE_SIMILARITY_THRESHOLD: f64 = 0.85;
22	pub const ABSTRACT_SIMILARITY_THRESHOLD: f64 = 0.80;
23	pub const ABSTRACT_COMPARE_LEN: usize = 200;
24	
25	#[derive(Clone)]
26	pub struct OutcomeService {
27	    pub db: SqlitePool,
28	}
29	
30	#[derive(Debug, Clone, Serialize, Deserialize)]
31	pub struct CreateOutcomeInput {
32	    pub r#type: String,
33	    pub title: String,
34	    pub abstract_snippet: String,
35	    pub certificate_number: Option<String>,
36	}
37	
38	#[derive(Debug, Clone, Serialize, Deserialize)]
39	pub struct DuplicateCandidate {
40	    pub id: String,
41	    pub title: String,
42	    pub similarity_score: f64,
43	    pub reason: String,
44	}
45	
46	#[derive(Debug, Clone, Serialize, Deserialize)]
47	pub struct CreateOutcomeResult {
48	    pub outcome: Outcome,
49	    pub duplicate_candidates: Vec<DuplicateCandidate>,
50	}

