1	//! Pure-function filter state used by the knowledge points table.
2	//! Lives in the frontend crate so it can be unit-tested without WASM.
3	
4	#[derive(Debug, Clone, PartialEq, Default)]
5	pub struct KnowledgeFilterState {
6	    pub chapter: Option<String>,
7	    pub tags: Vec<String>,
8	    pub difficulty_min: Option<i64>,
9	    pub difficulty_max: Option<i64>,
10	    pub discrimination_min: Option<f64>,
11	    pub discrimination_max: Option<f64>,
12	}
13	
14	impl KnowledgeFilterState {
15	    pub fn new() -> Self {
16	        Self::default()
17	    }
18	
19	    pub fn clear(&mut self) {
20	        *self = Self::default();
21	    }
22	
23	    pub fn add_tag(&mut self, tag: impl Into<String>) {
24	        let tag = tag.into();
25	        if !self.tags.contains(&tag) {
26	            self.tags.push(tag);
27	        }
28	    }
