316	        let mut purged_daily = 0i64;
317	        let mut purged_monthly = 0i64;
318	        let mut preserved_financial = 0i64;
319	        let mut preserved_ip = 0i64;
320	
321	        let candidates = sqlx::query_as::<_, BackupRecord>(
322	            "SELECT * FROM backup_records WHERE status = 'complete'",
