1	//! Cron-driven backup scheduler.
2	//!
3	//! Reads the `BACKUP_SCHEDULE` env var (default `"0 2 * * *"` — 02:00 daily)
4	//! and registers a `tokio_cron_scheduler` job that calls
5	//! `BackupService::run_backup` on the configured cadence. The scheduler is
6	//! started from `main.rs`; integration tests skip it.
7	
8	use std::sync::Arc;
9	
10	use tokio_cron_scheduler::{Job, JobScheduler};
11	
12	use crate::error::{AppError, AppResult};
13	use crate::services::backup_service::BackupService;
14	
15	/// Spawn the cron scheduler. Returns the running `JobScheduler` so the caller
16	/// can keep it alive for the lifetime of the process.
17	pub async fn start_backup_scheduler(
18	    service: Arc<BackupService>,
19	    cron_expr: &str,
20	) -> AppResult<JobScheduler> {
21	    let scheduler = JobScheduler::new()
22	        .await
23	        .map_err(|e| AppError::Internal(format!("scheduler init: {e}")))?;
24	    let svc = service.clone();
25	    let expr = cron_expr.to_string();
26	    let job = Job::new_async(expr.as_str(), move |_uuid, _l| {
27	        let svc = svc.clone();
28	        Box::pin(async move {
29	            match svc.run_backup().await {
30	                Ok(rec) => tracing::info!(id = %rec.id, ty = %rec.backup_type, "backup complete"),
31	                Err(e) => tracing::error!(error = ?e, "scheduled backup failed"),
32	            }
33	        })
34	    })
35	    .map_err(|e| AppError::Internal(format!("scheduler job: {e}")))?;
36	    scheduler
37	        .add(job)
38	        .await
39	        .map_err(|e| AppError::Internal(format!("scheduler add: {e}")))?;
40	    scheduler
41	        .start()
42	        .await
43	        .map_err(|e| AppError::Internal(format!("scheduler start: {e}")))?;
44	    tracing::info!(cron = %cron_expr, "backup scheduler started");
45	    Ok(scheduler)
46	}
