1	//! AES-256-GCM field-level encryption and the matching UI masking helper.
2	//!
3	//! Used for sensitive PII columns (`phone`, `national_id`) so the database row
4	//! never holds plaintext. Each call generates a fresh random nonce — encrypting
5	//! the same plaintext twice produces two different ciphertexts.
6	//!
7	//! On the UI side `mask_sensitive` returns the value with everything but the last
8	//! four characters replaced by `*`, matching the SPEC requirement for last-4
9	//! disclosure of sensitive fields.
10	
11	use aes_gcm::{
12	    aead::{Aead, AeadCore, KeyInit, OsRng},
13	    Aes256Gcm, Key, Nonce,
14	};
15	use base64::{engine::general_purpose::STANDARD as BASE64, Engine as _};
16	
17	use crate::error::{AppError, AppResult};
18	
19	const NONCE_LEN: usize = 12;
20	
21	/// Encrypt a sensitive field with AES-256-GCM. Output format is
22	/// `base64(nonce[12 bytes] || ciphertext)` so a single text column round-trips
23	/// the value end-to-end.
24	pub fn encrypt_field(plaintext: &str, key: &[u8; 32]) -> AppResult<String> {
25	    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(key));
26	    let nonce = Aes256Gcm::generate_nonce(&mut OsRng);
27	    let ciphertext = cipher
28	        .encrypt(&nonce, plaintext.as_bytes())
29	        .map_err(|_| AppError::Internal("aes-gcm encrypt failed".to_string()))?;
30	    let mut combined = Vec::with_capacity(NONCE_LEN + ciphertext.len());
31	    combined.extend_from_slice(nonce.as_slice());
32	    combined.extend_from_slice(&ciphertext);
33	    Ok(BASE64.encode(combined))
34	}
35	
36	/// Decrypt a value previously produced by `encrypt_field`. Splits the leading
37	/// 12-byte nonce off the buffer and runs AES-256-GCM in reverse with the same key.
38	pub fn decrypt_field(encoded: &str, key: &[u8; 32]) -> AppResult<String> {
39	    let data = BASE64
40	        .decode(encoded)
41	        .map_err(|e| AppError::Internal(format!("base64 decode: {e}")))?;
42	    if data.len() < NONCE_LEN {
43	        return Err(AppError::Internal("ciphertext too short".to_string()));
44	    }
45	    let (nonce_bytes, ciphertext) = data.split_at(NONCE_LEN);
46	    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(key));
47	    let plaintext = cipher
48	        .decrypt(Nonce::from_slice(nonce_bytes), ciphertext)
49	        .map_err(|_| AppError::Internal("aes-gcm decrypt failed".to_string()))?;
50	    String::from_utf8(plaintext).map_err(|e| AppError::Internal(format!("utf8: {e}")))
51	}
52	
53	/// Encrypt an arbitrary byte slice with AES-256-GCM. Output is the raw
54	/// `nonce[12] || ciphertext` byte sequence (no base64), suitable for binary
55	/// storage on disk such as backup bundles or encrypted evidence files.
56	pub fn encrypt_bytes(plaintext: &[u8], key: &[u8; 32]) -> AppResult<Vec<u8>> {
57	    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(key));
58	    let nonce = Aes256Gcm::generate_nonce(&mut OsRng);
59	    let ciphertext = cipher
60	        .encrypt(&nonce, plaintext)
61	        .map_err(|_| AppError::Internal("aes-gcm encrypt failed".to_string()))?;
62	    let mut combined = Vec::with_capacity(NONCE_LEN + ciphertext.len());
63	    combined.extend_from_slice(nonce.as_slice());
64	    combined.extend_from_slice(&ciphertext);
65	    Ok(combined)
66	}
67	
68	/// Reverse of `encrypt_bytes` — strips the nonce and runs AES-256-GCM in reverse.
69	pub fn decrypt_bytes(blob: &[u8], key: &[u8; 32]) -> AppResult<Vec<u8>> {
70	    if blob.len() < NONCE_LEN {
71	        return Err(AppError::Internal("ciphertext too short".to_string()));
72	    }
73	    let (nonce_bytes, ciphertext) = blob.split_at(NONCE_LEN);
74	    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(key));
75	    cipher
76	        .decrypt(Nonce::from_slice(nonce_bytes), ciphertext)
77	        .map_err(|_| AppError::Internal("aes-gcm decrypt failed".to_string()))
78	}
