80	/// Mask a sensitive value for UI display — show only the last 4 characters,
81	/// replace the rest with `*`. Operates on chars (not bytes) to handle non-ASCII
82	/// values safely. Example: `"9876543210"` → `"******3210"`.
83	pub fn mask_sensitive(value: &str) -> String {
84	    let chars: Vec<char> = value.chars().collect();
85	    let n = chars.len();
86	    if n == 0 {
87	        return String::new();
88	    }
89	    if n <= 4 {
90	        return "*".repeat(n);
91	    }
92	    let mut out = String::with_capacity(n);
93	    for _ in 0..(n - 4) {
94	        out.push('*');
95	    }
96	    for c in &chars[n - 4..] {
97	        out.push(*c);
98	    }
99	    out
100	}
