1	//! Backup tab — list history, run a backup, restore via sandbox validation,
2	//! lifecycle cleanup, retention policy display.
3	
4	use leptos::*;
5	use wasm_bindgen_futures::spawn_local;
6	
7	use crate::api::backup as backup_api;
8	
9	#[component]
10	pub fn BackupTab() -> impl IntoView {
11	    let history = create_resource(|| (), |_| async move { backup_api::list_history().await });
12	    let policy = create_resource(|| (), |_| async move { backup_api::get_policy().await });
13	    let (status, set_status) = create_signal::<Option<String>>(None);
14	    let (validation, set_validation) =
15	        create_signal::<Option<backup_api::SandboxValidationReport>>(None);
16	    let (validating_id, set_validating_id) = create_signal::<Option<String>>(None);
17	
18	    let run_backup = move |_| {
19	        spawn_local(async move {
20	            match backup_api::run_backup().await {
21	                Ok(b) => {
22	                    set_status.set(Some(format!("Created {} backup {}", b.backup_type, &b.id[..8])));
23	                    history.refetch();
24	                }
25	                Err(e) => set_status.set(Some(format!("Error: {}", e.message))),
26	            }
27	        });
28	    };
29	
30	    let cleanup = move |_| {
31	        spawn_local(async move {
32	            match backup_api::lifecycle_cleanup().await {
33	                Ok(r) => set_status.set(Some(format!(
34	                    "Purged {} daily / {} monthly • preserved {} fin / {} ip",
35	                    r.purged_daily, r.purged_monthly, r.preserved_financial, r.preserved_ip
36	                ))),
37	                Err(e) => set_status.set(Some(format!("Error: {}", e.message))),
38	            }
39	        });
40	    };
41	
42	    let validate = move |id: String| {
43	        set_validating_id.set(Some(id.clone()));
44	        spawn_local(async move {
45	            match backup_api::restore_sandbox(&id).await {
46	                Ok(r) => set_validation.set(Some(r)),
47	                Err(e) => set_status.set(Some(format!("Error: {}", e.message))),
48	            }
49	        });
50	    };
51	
52	    let activate = move |id: String| {
53	        spawn_local(async move {
54	            match backup_api::activate(&id).await {
55	                Ok(_) => set_status.set(Some(format!("Activated restore for {}", &id[..8]))),
56	                Err(e) => set_status.set(Some(format!("Activate failed: {}", e.message))),
57	            }
58	        });
59	    };
60	
61	    view! {
62	        <div style="display:grid;grid-template-columns:1.6fr 1fr;gap:24px;">
63	            <div class="sv-card">
64	                <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;">
65	                    <h2 style="margin:0;font-size:16px;color:#F5C518;">"Backup History"</h2>
66	                    <div style="display:flex;gap:8px;">
67	                        <button class="sv-btn-primary" on:click=run_backup>"Run Backup Now"</button>
68	                        <button class="sv-btn-secondary" on:click=cleanup>"Lifecycle Cleanup"</button>
69	                    </div>
70	                </div>
71	                <Suspense fallback=|| view! { <div class="sv-skeleton" style="height:160px;"></div> }>
72	                    {move || history.get().map(|res| match res {
73	                        Ok(rows) if rows.is_empty() => view! {
74	                            <div style="text-align:center;color:#A0A0B0;padding:24px;">"No backups yet — click Run Backup Now."</div>
75	                        }.into_view(),
76	                        Ok(rows) => view! {
77	                            <table class="sv-table">
78	                                <thead>
79	                                    <tr><th>"Type"</th><th>"Created"</th><th>"Size"</th><th>"Status"</th><th>"SHA-256"</th><th>"Actions"</th></tr>
80	                                </thead>
81	                                <tbody>
82	                                    {rows.into_iter().map(|r| {
83	                                        let badge = match r.status.as_str() {
84	                                            "complete" => "sv-badge sv-badge-success",
85	                                            "purged" => "sv-badge sv-badge-warning",
86	                                            _ => "sv-badge sv-badge-info",
87	                                        };
88	                                        let id_for_validate = r.id.clone();
89	                                        let id_for_activate = r.id.clone();
90	                                        view! {
91	                                            <tr>
92	                                                <td><span class="sv-badge sv-badge-info">{r.backup_type.clone()}</span></td>
93	                                                <td style="font-size:11px;color:#A0A0B0;">{r.created_at.clone()}</td>
94	                                                <td>{format!("{} KB", r.size_bytes / 1024)}</td>
95	                                                <td><span class=badge>{r.status.clone()}</span></td>
96	                                                <td style="font-family:monospace;font-size:10px;">{format!("{}…", &r.sha256_hash[..12])}</td>
97	                                                <td>
98	                                                    <button class="sv-btn-ghost" style="font-size:11px;padding:4px 8px;"
99	                                                        on:click=move |_| validate(id_for_validate.clone())>"Validate"</button>
100	                                                    <button class="sv-btn-ghost" style="font-size:11px;padding:4px 8px;"
101	                                                        on:click=move |_| activate(id_for_activate.clone())>"Activate"</button>
102	                                                </td>
103	                                            </tr>
104	                                        }
105	                                    }).collect_view()}
106	                                </tbody>
107	                            </table>
108	                        }.into_view(),
109	                        Err(e) => view! { <div class="sv-error">{e.message}</div> }.into_view(),
110	                    })}
111	                </Suspense>
112	                {move || status.get().map(|s| view! {
113	                    <div style="margin-top:14px;font-size:12px;color:#A0A0B0;">{s}</div>
114	                })}
115	            </div>
116	
117	            <div style="display:flex;flex-direction:column;gap:16px;">
118	                <div class="sv-card">
119	                    <h3 style="margin:0 0 12px;font-size:14px;color:#F5C518;">"Retention Policy"</h3>
120	                    <Suspense fallback=|| view! { <div class="sv-skeleton" style="height:80px;"></div> }>
121	                        {move || policy.get().map(|res| match res {
122	                            Ok(p) => view! {
123	                                <div style="font-size:12px;line-height:1.8;">
124	                                    <div>{format!("Daily backups kept: {}", p.daily_retention)}</div>
125	                                    <div>{format!("Monthly backups kept: {}", p.monthly_retention)}</div>
126	                                    <div>{format!("Preserve financial: {}", if p.preserve_financial == 1 { "yes" } else { "no" })}</div>
127	                                    <div>{format!("Preserve IP: {}", if p.preserve_ip == 1 { "yes" } else { "no" })}</div>
128	                                </div>
129	                            }.into_view(),
130	                            Err(e) => view! { <div class="sv-error">{e.message}</div> }.into_view(),
131	                        })}
132	                    </Suspense>
133	                </div>
134	
135	                {move || validation.get().map(|r| {
136	                    let id = validating_id.get().unwrap_or_default();
137	                    let badge = if r.all_passed { "sv-badge sv-badge-success" } else { "sv-badge sv-badge-danger" };
138	                    view! {
139	                        <div class="sv-card">
140	                            <h3 style="margin:0 0 12px;font-size:14px;color:#F5C518;">{format!("Sandbox: {}", id)}</h3>
141	                            <div style="display:flex;flex-direction:column;gap:6px;font-size:12px;">
142	                                <div>{format!("Hash check: {}", if r.hash_ok { "✓" } else { "✗" })}</div>
143	                                <div>{format!("PRAGMA integrity_check: {}", if r.integrity_ok { "✓" } else { "✗" })}</div>
144	                                <div>{format!("Read test (SELECT users): {}", if r.read_test_ok { "✓" } else { "✗" })}</div>
145	                                <div style="margin-top:8px;"><span class=badge>{if r.all_passed { "ALL PASSED" } else { "BLOCKED" }}</span></div>
146	                                <div style="margin-top:6px;color:#A0A0B0;font-size:11px;">{r.message}</div>
147	                            </div>
148	                        </div>
149	                    }
150	                })}
151	            </div>
152	        </div>
153	    }
154	}
