57	    post_json(&format!("/api/backup/{}/restore-sandbox", id), &serde_json::json!({})).await
58	}
59	
60	pub async fn activate(id: &str) -> Result<serde_json::Value, ApiError> {
61	    post_json(&format!("/api/backup/{}/activate", id), &serde_json::json!({})).await
62	}
