1	//! Outcome / IP HTTP handlers — list, register, contributors, evidence upload,
2	//! submit, side-by-side compare. Every mutation writes an audit log row.
3	
4	use axum::{
5	    extract::{Multipart, Path, State},
6	    Json,
7	};
8	use serde::{Deserialize, Serialize};
9	use serde_json::json;
10	use shared::AuditAction;
11	
12	use crate::error::{AppError, AppResult};
13	use crate::middleware::require_role::{AuthenticatedUser, RequireReviewer};
14	use crate::models::outcome::{EvidenceFile, Outcome, OutcomeContributor};
15	use crate::services::audit_service::AuditService;
16	use crate::services::file_service::FileService;
17	use crate::services::outcome_service::{
18	    AddContributorInput, CreateOutcomeInput, CreateOutcomeResult, DuplicateCandidate,
19	    OutcomeService,
20	};
21	use crate::AppState;
22	
23	fn outcome_privileged(role: &str) -> bool {
24	    matches!(
25	        shared::UserRole::from_str(role),
26	        Some(shared::UserRole::Administrator) | Some(shared::UserRole::Reviewer)
27	    )
28	}
29	
30	pub async fn list_outcomes(
31	    State(state): State<AppState>,
32	    AuthenticatedUser(user): AuthenticatedUser,
33	) -> AppResult<Json<Vec<Outcome>>> {
34	    let svc = OutcomeService::new(state.db.clone());
35	    let privileged = outcome_privileged(&user.role);
36	    Ok(Json(
37	        svc.list_outcomes_scoped(&user.id, privileged, 200).await?,
38	    ))
39	}
40	
41	pub async fn get_outcome(
42	    State(state): State<AppState>,
43	    AuthenticatedUser(user): AuthenticatedUser,
44	    Path(id): Path<String>,
45	) -> AppResult<Json<OutcomeWithEvidence>> {
46	    let svc = OutcomeService::new(state.db.clone());
47	    let privileged = outcome_privileged(&user.role);
48	    let outcome = svc.get_outcome_scoped(&id, &user.id, privileged).await?;
49	    let contributors = svc.list_contributors(&id).await?;
50	    let file_svc = FileService::new(
51	        state.db.clone(),
52	        *state.encryption_key,
53	        (*state.evidence_dir).clone(),
54	    );
55	    let evidence = file_svc.list_for_outcome(&id).await?;
56	    Ok(Json(OutcomeWithEvidence {
57	        outcome,
58	        contributors,
59	        evidence,
60	    }))
61	}
62	
63	#[derive(Debug, Serialize)]
64	pub struct OutcomeWithEvidence {
65	    pub outcome: Outcome,
66	    pub contributors: Vec<OutcomeContributor>,
67	    pub evidence: Vec<EvidenceFile>,
68	}
69	
70	pub async fn create_outcome(
71	    State(state): State<AppState>,
72	    RequireReviewer(user): RequireReviewer,
73	    Json(input): Json<CreateOutcomeInput>,
74	) -> AppResult<Json<CreateOutcomeResult>> {
75	    let svc = OutcomeService::new(state.db.clone());
76	    let result = svc.create_outcome(input, &user.id).await?;
77	    AuditService::new(state.db.clone())
78	        .log(
79	            &user.id,
80	            AuditAction::Create,
81	            "outcome",
82	            Some(&result.outcome.id),
83	            None,
84	            Some(AuditService::compute_hash(
85	                &serde_json::to_string(&result.outcome)?,
86	            )),
87	            None,
88	        )
89	        .await?;
90	    Ok(Json(result))
91	}
92	
93	pub async fn add_contributor(
94	    State(state): State<AppState>,
95	    RequireReviewer(user): RequireReviewer,
96	    Path(outcome_id): Path<String>,
97	    Json(input): Json<AddContributorInput>,
98	) -> AppResult<Json<OutcomeContributor>> {
99	    let svc = OutcomeService::new(state.db.clone());
100	    let row = svc.add_contributor(&outcome_id, input).await?;
101	    AuditService::new(state.db.clone())
102	        .log(
103	            &user.id,
104	            AuditAction::Update,
105	            "outcome_contributor",
106	            Some(&outcome_id),
107	            None,
108	            Some(AuditService::compute_hash(&serde_json::to_string(&row)?)),
109	            None,
110	        )
111	        .await?;
112	    Ok(Json(row))
113	}
114	
115	pub async fn remove_contributor(
116	    State(state): State<AppState>,
