206	pub async fn upload_evidence(
207	    State(state): State<AppState>,
208	    RequireReviewer(user): RequireReviewer,
209	    Path(outcome_id): Path<String>,
210	    mut multipart: Multipart,
211	) -> AppResult<Json<EvidenceFile>> {
212	    let mut bytes_field: Option<Vec<u8>> = None;
213	    let mut filename = String::from("upload.bin");
214	    let mut declared_mime = String::from("application/octet-stream");
215	
216	    while let Some(field) = multipart
217	        .next_field()
218	        .await
219	        .map_err(|e| AppError::Validation(format!("multipart: {e}")))?
220	    {
221	        let name = field.name().unwrap_or("").to_string();
222	        if name == "file" {
223	            if let Some(fname) = field.file_name() {
224	                filename = fname.to_string();
225	            }
226	            if let Some(ct) = field.content_type() {
227	                declared_mime = ct.to_string();
228	            }
229	            let data = field
230	                .bytes()
231	                .await
232	                .map_err(|e| AppError::Validation(format!("multipart bytes: {e}")))?;
233	            bytes_field = Some(data.to_vec());
234	        }
235	    }
236	    let bytes = bytes_field.ok_or_else(|| AppError::Validation("missing 'file' field".into()))?;
237	
238	    let file_svc = FileService::new(
239	        state.db.clone(),
240	        *state.encryption_key,
241	        (*state.evidence_dir).clone(),
242	    );
243	    let row = file_svc
244	        .upload_evidence(&outcome_id, &bytes, &filename, &declared_mime, &user.id)
245	        .await?;
246	    AuditService::new(state.db.clone())
247	        .log(
248	            &user.id,
249	            AuditAction::UploadEvidence,
250	            "evidence_file",
251	            Some(&row.id),
252	            None,
253	            Some(AuditService::compute_hash(&row.sha256_fingerprint)),
254	            None,
255	        )
256	        .await?;
257	    Ok(Json(row))
258	}
