73	/// POST /api/auth/login
74	pub async fn login(
75	    State(state): State<AppState>,
76	    cookies: CookieJar,
77	    addr: Option<ConnectInfo<SocketAddr>>,
78	    Json(req): Json<LoginRequest>,
79	) -> AppResult<(CookieJar, Json<LoginResponse>)> {
80	    if req.username.trim().is_empty() || req.password.is_empty() {
81	        return Err(AppError::Validation(
82	            "username and password are required".to_string(),
83	        ));
84	    }
85	
86	    let ip = addr
87	        .map(|c| c.0.ip().to_string())
88	        .unwrap_or_else(|| "0.0.0.0".to_string());
89	    let auth = AuthService::new(state.db.clone());
90	    let outcome = auth.login(&req.username, &req.password, &ip).await?;
91	
92	    let secure = cookies_secure();
93	    let session_cookie = Cookie::build(("sv_session", outcome.session_id.clone()))
94	        .http_only(true)
95	        .secure(secure)
96	        .same_site(SameSite::Lax)
97	        .path("/")
98	        .build();
99	    let csrf_cookie = Cookie::build(("csrf_token", outcome.csrf_token.clone()))
